import { useState, useEffect, useContext } from 'react';
import { CartContext } from '../context/CartContext';
import { useNavigate } from 'react-router-dom';
import { X, Trash2, ShoppingCart, Plus, Minus, ArrowRight } from 'lucide-react';

const Cart = ({ isOpen, onClose }) => {
    const navigate = useNavigate();
    const { cart, removeFromCart, updateQuantity, clearCart } = useContext(CartContext);

    const [isAnimating, setIsAnimating] = useState(false);
    const [removingId, setRemovingId] = useState(null);
    const [localIsOpen, setLocalIsOpen] = useState(false);

    // Tính tổng số lượng sản phẩm
    const totalItems = cart ? cart.reduce((sum, item) => sum + (item.qty || 1), 0) : 0;

    // Tính tổng tiền 
    const cartTotal = cart ? cart.reduce((sum, item) => sum + (item.price * (item.qty || 1)), 0) : 0;

    // Lắng nghe tín hiệu từ Navbar phát ra để mở giỏ hàng
    useEffect(() => {
        const handleOpen = () => {
            setIsAnimating(true);
        };
        window.addEventListener('openCartGlobal', handleOpen);
        return () => window.removeEventListener('openCartGlobal', handleOpen);
    }, []);

 

    // Hiệu ứng xóa sản phẩm
    const handleRemove = async (itemId) => {
        setRemovingId(itemId);
        setTimeout(() => {
            removeFromCart(itemId);
            setRemovingId(null);
        }, 300);
    };

    const handleCheckout = () => {
        if (onClose) onClose();
        setTimeout(() => navigate('/checkout'), 300);
    };

    if (!isOpen) return null;

    return (
        <div
            className={`fixed inset-0 z-[1000] flex justify-end transition-colors duration-300 ${
                isAnimating ? 'bg-black/60' : 'bg-black/0'
            }`}
            onClick={onClose}
            role="dialog"
            aria-modal="true"
            aria-label="Giỏ hàng"
        >
            <div
                className={`w-full max-w-md h-full bg-white shadow-2xl flex flex-col 
                    transition-transform duration-300 ease-out ${
                        isAnimating ? 'translate-x-0' : 'translate-x-full'
                    }`}
                onClick={e => e.stopPropagation()}
            >
                {/* Header */}
                <CartHeader
                    totalItems={totalItems}
                    onClose={onClose}
                    onClear={clearCart}
                    hasItems={cart && cart.length > 0}
                />

                {/* Danh sách Items */}
                <div className="flex-1 overflow-y-auto p-6 space-y-4">
                    {cart?.length === 0 ? (
                        <EmptyCart onClose={onClose} navigate={navigate} />
                    ) : (
                        cart?.map(item => {
                            if (!item?.id) return null;
                            return (
                                <CartItem
                                    key={item.id}
                                    item={item}
                                    isRemoving={removingId === item.id}
                                    onRemove={handleRemove}
                                    onUpdateQuantity={updateQuantity}
                                />
                            );
                        })
                    )}
                </div>

                {/* Footer */}
                {cart?.length > 0 && (
                    <CartFooter
                        cartTotal={cartTotal}
                        onCheckout={handleCheckout}
                    />
                )}
            </div>
        </div>
    );
};

// Component con: Tiêu đề giỏ hàng
const CartHeader = ({ totalItems, onClose, onClear, hasItems }) => (
    <div className="flex items-center justify-between p-6 border-b bg-white sticky top-0">
        <div className="flex items-center gap-3">
            <ShoppingCart className="text-green-600" size={24} />
            <h2 className="text-2xl font-bold text-green-700">
                Giỏ hàng
                <span className="ml-2 text-sm font-normal text-gray-500">
                    ({totalItems} sản phẩm)
                </span>
            </h2>
        </div>
        <div className="flex items-center gap-2">
            {hasItems && (
                <button
                    onClick={onClear}
                    className="text-xs text-red-400 hover:text-red-600 px-2 py-1 hover:bg-red-50 rounded transition-colors"
                >
                    Xóa tất cả
                </button>
            )}
            <button
                onClick={onClose}
                className="p-2 hover:bg-gray-100 rounded-full transition-colors"
            >
                <X size={24} />
            </button>
        </div>
    </div>
);

// Component con: Từng hàng sản phẩm
const CartItem = ({ item, isRemoving, onRemove, onUpdateQuantity }) => {
    const subtotal = (item.price || 0) * (item.qty || 1);

    return (
        <div className={`flex gap-4 border-b pb-4 transition-all duration-300 ${
            isRemoving ? 'opacity-0 scale-95 -translate-x-4' : 'opacity-100 scale-100'
        }`}>
            <div className="w-20 h-20 bg-gradient-to-br from-green-400 to-emerald-500 rounded-2xl flex items-center justify-center text-4xl text-white font-bold shrink-0">
                {item.image ? (
                    <img src={item.image} alt={item.name} className="w-full h-full object-cover rounded-2xl" />
                ) : (
                    item.name?.charAt(0).toUpperCase() || '?'
                )}
            </div>

            <div className="flex-1 min-w-0">
                <h4 className="font-semibold text-gray-800 truncate">
                    {item.name || 'Sản phẩm không xác định'}
                </h4>
                <p className="text-gray-400 text-sm mt-0.5">
                    {Number(item.price || 0).toLocaleString('vi-VN')}đ
                </p>
                <div className="flex items-center gap-3 mt-2">
                    <QuantityButton
                        onClick={() => onUpdateQuantity(item.id, (item.qty || 1) - 1)}
                        disabled={(item.qty || 1) <= 1}
                    >
                        <Minus size={12} />
                    </QuantityButton>

                    <span className="font-medium w-8 text-center tabular-nums">
                        {item.qty || 1}
                    </span>

                    <QuantityButton onClick={() => onUpdateQuantity(item.id, (item.qty || 1) + 1)}>
                        <Plus size={12} />
                    </QuantityButton>

                    <span className="ml-auto text-green-600 font-bold text-sm">
                        {subtotal.toLocaleString('vi-VN')}đ
                    </span>
                </div>
            </div>

            <button
                onClick={() => onRemove(item.id)}
                className="text-red-400 hover:text-red-600 p-1 hover:bg-red-50 rounded-lg transition-colors self-start"
            >
                <Trash2 size={18} />
            </button>
        </div>
    );
};

const QuantityButton = ({ children, disabled, onClick, ...props }) => (
    <button
        onClick={onClick}
        disabled={disabled}
        className={`border w-8 h-8 rounded-lg flex items-center justify-center transition-colors ${
            disabled ? 'opacity-30 cursor-not-allowed' : 'hover:bg-gray-100 active:bg-gray-200'
        }`}
        {...props}
    >
        {children}
    </button>
);

// Component con: Giao diện khi giỏ trống trống
const EmptyCart = ({ onClose, navigate }) => (
    <div className="flex flex-col items-center justify-center h-full gap-4 py-16">
        <div className="w-24 h-24 bg-gray-100 rounded-full flex items-center justify-center">
            <ShoppingCart size={40} className="text-gray-300" />
        </div>
        <p className="text-gray-400 text-lg font-medium">Giỏ hàng trống</p>
        <p className="text-gray-300 text-sm text-center">Hãy thêm sản phẩm vào giỏ hàng của bạn</p>
        <button
            onClick={() => {
                if (navigate) navigate("/"); 
                if (onClose) onClose();  
            }}
            className="text-green-600 font-medium hover:underline mt-2"
        >
            Tiếp tục mua sắm →
        </button>
    </div>
);

// Component con: Phần thanh toán dưới cùng
const CartFooter = ({ cartTotal, onCheckout }) => (
    <div className="p-6 border-t bg-gray-50">
        <div className="flex justify-between text-sm text-gray-500 mb-2">
            <span>Tạm tính:</span>
            <span>{Number(cartTotal || 0).toLocaleString('vi-VN')}đ</span>
        </div>
        <div className="flex justify-between text-sm text-gray-500 mb-4">
            <span>Phí vận chuyển:</span>
            <span className="text-green-600 font-medium">Miễn phí</span>
        </div>
        <div className="border-t pt-4 flex justify-between text-xl font-bold mb-6">
            <span>Tổng tiền:</span>
            <span className="text-green-600">{Number(cartTotal || 0).toLocaleString('vi-VN')}đ</span>
        </div>
        <button
            onClick={onCheckout}
            className="w-full bg-green-600 hover:bg-green-700 active:bg-green-800 text-white py-4 rounded-2xl font-bold transition-colors flex items-center justify-center gap-2"
        >
            Thanh toán ngay
            <ArrowRight size={20} />
        </button>
    </div>
);

export default Cart;
